            'state': state
        })

state_counts = Counter([b['state'] for b in businesses_with_state])
sorted_states = state_counts.most_common()

top_state = sorted_states[0] if sorted_states else None

output = {
    'wifi_businesses': len(wifi_businesses),
    'with_state': len(businesses_with_state),
    'top_state': top_state,
    'state_counts': sorted_states[:10]
}

print('__RESULT__:')
